func TestGetTopicDetailHandlerMedium(t *testing.T) {
	ctx := context.Background()
	pool, err := pgxpool.New(ctx, "postgresql://postgres:password@localhost:5432/postgres")
	if err != nil {
		log.Fatal(err)
	}
	defer pool.Close()

	q := db.New(pool)
	handler := NewTopicDetailHandler(q)

	t.Run("published な講座のトピック詳細が取得できる", func(t *testing.T) {
		w := httptest.NewRecorder()
		h := httptest.NewRequest("GET", "/topics/123", nil)

		pool.Exec(context.Background(), "INSERT INTO courses (course_id, title, description, slug, tags, publish_status,category_id, published_at, author_id, visibility) VALUES ()")

		handler.GetTopicDetailHandler(w, h)
	})

	t.Run("自分が作成した draft な講座のトピック詳細が取得できる", func(t *testing.T) {

	})

	t.Run("他人が作成した draft な講座のトピック詳細ができない", func(t *testing.T) {

	})

	t.Run("存在しないトピックの詳細が取得できない", func(t *testing.T) {

	})
}

